      }
    }
  },
  "common_scenarios": {
    "full_workflow": {
      "description": "Complete workflow: create project, add tasks, update status",
      "steps": [
        {
          "step": 1,
          "action": "POST /projects",
          "request_ref": "endpoints./projects.create.request",
          "response_ref": "endpoints./projects.create.response.success"
        },
        {
          "step": 2,
          "action": "POST /tasks",
          "request_ref": "endpoints./tasks.create.request",
          "request_override": {
            "body": {
              "project_id": "{{ step_1.response.body.id }}"
            }
          }
        },
        {
          "step": 3,
          "action": "PUT /tasks/{id}",
          "request_ref": "endpoints./tasks.update.request",
          "path_params": {
            "id": "{{ step_2.response.body.id }}"
          }
        }
      ]
    }
  }
